sql:
SELECT SUM(initial_approval) AS total_initial_approvals
FROM h1b_applications
WHERE state = 'OK';

external_knowledge:
- H1B visa: a non-immigrant visa in the United States that allows U.S. employers to temporarily employ foreign workers in specialty occupations; 
- NAICS code: North American Industry Classification System code, used to classify businesses for the purpose of collecting, analyzing, and publishing statistical data related to the U.S. business economy;
- Fiscal year: a period used for calculating annual ("yearly") financial reports in businesses and organizations; 
- Application status: the current stage or condition of an application (e.g., approved, denied).

sql:
SELECT DISTINCT job_title
FROM h1b_applications
WHERE fiscal_year = 2022 AND initial_approval > 0;

SELECT AVG(initial_approval) AS average_initial_approval
FROM h1b_applications
WHERE application_status_id = (SELECT status_id FROM application_status WHERE status_name = 'initial approval');

SELECT DISTINCT fiscal_year
    FROM h1b_applications
    ORDER BY fiscal_year ASC;

SELECT job_title
FROM h1b_applications
WHERE application_id = 1;
